    let pool_id = env.register(ShieldedPool, ());
    let pool = ShieldedPoolClient::new(&env, &pool_id);
    pool.init(&admin, &token, &HIGH_THRESHOLD);

    let swap = fx::swap_fixture();
    pool.confidential_swap(&b64(&env, &swap.a), &b128(&env, &swap.b), &b64(&env, &swap.c),
        &sigs(&env, swap.public_signals), &b32(&env, &[9u8; 32]));
