#[test]
fn refund_after_timeout() {
    let env = Env::default();
    env.cost_estimate().budget().reset_unlimited();
    let c = setup(&env);
    let swap = fx::swap_fixture();
    let swap_id = c.pool.confidential_swap(&b64(&env, &swap.a), &b128(&env, &swap.b),
        &b64(&env, &swap.c), &sigs(&env, swap.public_signals), &b32(&env, &[9u8; 32]));

    env.ledger().with_mut(|l| l.timestamp += 3601);
    c.pool.refund_swap(&swap_id);
    assert!(c.pool.get_payout(&swap_id).status == SwapStatus::Refunded);
}

#[test]
fn unshield_pays_recipient_and_nullifies() {
    let env = Env::default();
    env.cost_estimate().budget().reset_unlimited();
    let c = setup(&env);
    let swap = fx::swap_fixture(); // proves a note worth >= 250, amount = 250
    let recipient = Address::generate(&env);

    c.pool.unshield(&b64(&env, &swap.a), &b128(&env, &swap.b), &b64(&env, &swap.c),
        &sigs(&env, swap.public_signals), &recipient);

    // crypto landed in the recipient wallet; pool retains the rest
    let tok = TokenClient::new(&env, &c.token);
    assert_eq!(tok.balance(&recipient), 250);
    assert_eq!(tok.balance(&c.pool_id), 750);
}

#[test]
fn shielded_transfer_enqueues_two_outputs() {
    let env = Env::default();
    env.cost_estimate().budget().reset_unlimited();
    let c = setup(&env);
    let t = fx::transfer_fixture(); // spends the seed note (index 0) -> recipient + change
    c.pool.shielded_transfer(&b64(&env, &t.a), &b128(&env, &t.b), &b64(&env, &t.c), &sigs(&env, t.public_signals));
    // transfer enqueues both outputs (no insert here) -> tree index unchanged
    assert_eq!(c.pool.next_index(), 1);
}

#[test]
#[should_panic(expected = "nullifier already spent")]
fn shielded_transfer_double_spend_rejected() {
    let env = Env::default();
    env.cost_estimate().budget().reset_unlimited();
    let c = setup(&env);
    let t = fx::transfer_fixture();
    c.pool.shielded_transfer(&b64(&env, &t.a), &b128(&env, &t.b), &b64(&env, &t.c), &sigs(&env, t.public_signals));
    c.pool.shielded_transfer(&b64(&env, &t.a), &b128(&env, &t.b), &b64(&env, &t.c), &sigs(&env, t.public_signals));
}

#[test]
#[should_panic(expected = "nullifier already spent")]
fn unshield_then_swap_same_note_rejected() {
    let env = Env::default();
    env.cost_estimate().budget().reset_unlimited();
    let c = setup(&env);
    let swap = fx::swap_fixture();
    let recipient = Address::generate(&env);
    c.pool.unshield(&b64(&env, &swap.a), &b128(&env, &swap.b), &b64(&env, &swap.c),
        &sigs(&env, swap.public_signals), &recipient);
    // reusing the same note (nullifier) for a swap must fail
    c.pool.confidential_swap(&b64(&env, &swap.a), &b128(&env, &swap.b), &b64(&env, &swap.c),
        &sigs(&env, swap.public_signals), &b32(&env, &[9u8; 32]));
}
